const data = $input.first().json;
const negocio = data.negocio || 'Mi Negocio';
const periodo = data.periodo || 'ultima-semana';
const email = data.email;
const periodoMap = {'ultima-semana':'Última Semana','ultimo-mes':'Último Mes','ultimo-trimestre':'Último Trimestre'};
const periodoLabel = periodoMap[periodo] || periodo;

// Datos de demostración realistas
const r = (min,max) => Math.floor(Math.random()*(max-min+1))+min;
const ventas = r(15000,85000);
const ventasAnt = r(12000,80000);
const cambio = (((ventas-ventasAnt)/ventasAnt)*100).toFixed(1);
const cambioSign = cambio >= 0 ? '+' : '';
const cambioColor = cambio >= 0 ? '#22c55e' : '#ef4444';
const clientes = r(40,200);
const ticketProm = r(150,800);
const topProducto = ['Servicio Premium','Consultoría Express','Plan Mensual','Paquete Anual','Setup Inicial'][r(0,4)];
const satisfaccion = r(85,99);

const acciones = [
  {icon:'📈',text:`Ventas ${cambioSign}${cambio}% vs período anterior — ${cambio>=0?'mantener estrategia actual':'revisar pricing y canales de adquisición'}`},
  {icon:'🎯',text:`Top producto: ${topProducto} (${r(30,60)}% del revenue) — considerar bundle o upsell`},
  {icon:'👥',text:`${clientes} clientes activos con ticket promedio $${ticketProm.toLocaleString()} — oportunidad de incrementar valor por cliente`}
];

const html = `<div style='font-family:Arial,sans-serif;max-width:640px;margin:0 auto;background:#f8fafc;padding:24px'>
<div style='background:white;border-radius:12px;padding:32px;box-shadow:0 1px 3px rgba(0,0,0,.1)'>
<div style='display:flex;align-items:center;gap:12px;margin-bottom:24px'><div style='width:48px;height:48px;border-radius:12px;background:#2E7BF6;display:flex;align-items:center;justify-content:center'><span style='font-size:24px'>📊</span></div><div><h1 style='margin:0;font-size:20px;color:#1e293b'>Reporte ${periodoLabel}</h1><p style='margin:0;font-size:14px;color:#64748b'>${negocio}</p></div></div>

<div style='display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:24px'>
<div style='background:#f0f9ff;border:1px solid #bae6fd;border-radius:8px;padding:16px;text-align:center'><div style='font-size:24px;font-weight:800;color:#0369a1'>$${ventas.toLocaleString()}</div><div style='font-size:12px;color:#64748b;margin-top:4px'>Ventas totales</div></div>
<div style='background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:16px;text-align:center'><div style='font-size:24px;font-weight:800;color:${cambioColor}'>${cambioSign}${cambio}%</div><div style='font-size:12px;color:#64748b;margin-top:4px'>vs período anterior</div></div>
<div style='background:#fefce8;border:1px solid #fef08a;border-radius:8px;padding:16px;text-align:center'><div style='font-size:24px;font-weight:800;color:#a16207'>${clientes}</div><div style='font-size:12px;color:#64748b;margin-top:4px'>Clientes activos</div></div>
<div style='background:#fdf4ff;border:1px solid #f5d0fe;border-radius:8px;padding:16px;text-align:center'><div style='font-size:24px;font-weight:800;color:#86198f'>${satisfaccion}%</div><div style='font-size:12px;color:#64748b;margin-top:4px'>Satisfacción</div></div>
</div>

<h2 style='font-size:16px;color:#1e293b;margin:0 0 16px'>Acciones Recomendadas</h2>
${acciones.map(a => `<div style='background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;padding:14px 16px;margin-bottom:8px;font-size:14px;color:#334155;line-height:1.6'>${a.icon} ${a.text}</div>`).join('')}

<div style='margin-top:24px;padding-top:16px;border-top:1px solid #e2e8f0;font-size:12px;color:#94a3b8;text-align:center'>Generado automáticamente por Luis Moreno — Automatización para Negocios</div>
</div></div>`;

return [{json:{email,negocio,periodo:periodoLabel,html,asunto:`Reporte ${periodoLabel} — ${negocio}`}}];
